############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(1.1.6.43) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGchoicemacros.pl", "contextCurrency.pl", "contextPercent.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("Percent"); ($p, $q) = map{Percent($_*0.005 + 0.01)} (0..4)[NchooseK(5,2)]; Context("Currency"); Context()->currency->addSymbol("dollars", "dollar"); Context()->flags->set(trimTrailingZeros => 1); $original = random(9, 11, 0.25); $current = Currency(round($original*(1 + $p->value)*(1 + $q->value))); $original = Currency($current / (1 + $p) / (1 + $q));
############################################################ # Body ############################################################
BEGIN_PGML Last year, Joan received a [`[$p]`] raise. This year, she received a [`[$q]`] raise. Her current wage is [`[$current]`] an hour. What was her wage before the two raises?
[_]{$original}{10}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION We can represent this situation with the equation: [` x \cdot (1 + [$p->value]) \cdot (1 + [$q->value]) = [$current->value]\text{.}`] Solve this equation for [`x\text{.}`]
END_PGML_SOLUTION
############################################################ # End Problem ############################################################
ENDDOCUMENT();
